(13,	'Nomina AdS',	'<h1 style=\"line-height:1.2;margin-top:12pt;margin-bottom:12pt;\"><span style=\"font-size:24pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Nomina Amministratore di Sistema (AdS)</strong></span></h1><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><em>Ai sensi del Provvedimento del Garante per la protezione dei dati personali del 27 novembre 2008 e del GDPR 2016/679.</em></span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>1. Dati del Soggetto Nominato</strong></span></h2><table style=\"border:none;border-collapse:collapse;\"><tbody><tr style=\"height:0pt;\"><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;background-color:#f9f9f9;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Nominativo:</strong></span></p></td><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">[Nome e Cognome]</span></p></td></tr><tr style=\"height:0pt;\"><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;background-color:#f9f9f9;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Ruolo Aziendale:</strong></span></p></td><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">[es. Responsabile IT / Sistemista]</span></p></td></tr><tr style=\"height:0pt;\"><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;background-color:#f9f9f9;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Data della Nomina:</strong></span></p></td><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">[Data odierna]</span></p></td></tr></tbody></table><h2 style=\"line-height:1.2;margin-top:11.25pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>2. Ambiti di Operatività</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il soggetto viene nominato Amministratore di Sistema per le seguenti risorse informatiche:</span></p><ul style=\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\"><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Gestione del CRM aziendale e Database Lead.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Gestione del Software di Chiamata (Dialer) e Registrazioni Audio.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Amministrazione dei Server (Cloud/On-premise) e delle Reti (VPN).</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Gestione degli account email e delle credenziali degli operatori.</span></p></li></ul><h2 style=\"line-height:1.2;margin-top:11.25pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>3. Istruzioni e Obblighi</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">L&#039;Amministratore di Sistema è tenuto ad osservare le seguenti istruzioni:</span></p><ul style=\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\"><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Gestione Log:</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Assicurare la registrazione degli accessi logici (Log-in) ai sistemi. I log devono essere inalterabili, completi e conservati per almeno </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>6 mesi</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Credenziali:</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Adottare e far adottare policy per password sicure (min. 8 caratteri, alfanumeriche) e cambio obbligatorio periodico.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Disaster Recovery:</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Supervisionare le procedure di backup e verificare periodicamente l&#039;integrità dei dati salvati.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Riservatezza:</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Mantenere il segreto assoluto sui dati di cui viene a conoscenza durante l&#039;espletamento delle proprie funzioni tecniche.</span></p></li></ul><h2 style=\"line-height:1.2;margin-top:11.25pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>4. Verifiche</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:22.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il Titolare del trattamento o il DPO effettueranno verifiche periodiche (almeno annuali) per accertare la conformità dell&#039;operato dell&#039;AdS alle presenti istruzioni e alle misure di sicurezza vigenti.</span></p><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Firma del Titolare: ____________________</span></p><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Firma per accettazione dell&#039;AdS: ____________________</span></p><p><br></p>',	1,	NULL,	NULL,	'2026-04-25 08:44:25',	'2026-04-25 08:44:25'),
(14,	'Nomina Responsabile agenzia call center',	'<h1 style=\"line-height:1.2;margin-top:12pt;margin-bottom:12pt;\"><span style=\"font-size:24pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Nomina a Sub-Responsabile del Trattamento (Art. 28 GDPR)</strong></span></h1><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Tra </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>[Ragione Sociale del tuo Call Center]</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, con sede in [Indirizzo], P.IVA [Partita IVA], d&#039;ora in avanti il &quot;Responsabile&quot;;</span></p><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">e </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>[Ragione Sociale della Sub-Agenzia]</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, con sede in [Indirizzo], P.IVA [Partita IVA], d&#039;ora in avanti il &quot;Sub-Responsabile&quot;.</span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>1. Oggetto e Durata</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il Responsabile affida al Sub-Responsabile le attività di telemarketing e gestione contatti per conto della Mandante [Nome Utility]. Il presente contratto ha validità fino alla cessazione dell&#039;incarico commerciale tra le parti.</span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>2. Obblighi del Sub-Responsabile</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il Sub-Responsabile si impegna a:</span></p><ul style=\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\"><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Trattare i dati personali esclusivamente sulla base delle istruzioni documentate fornite dal Responsabile.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Garantire che le persone autorizzate al trattamento dei dati personali si siano impegnate alla riservatezza o abbiano un adeguato obbligo legale di riservatezza.</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Adottare tutte le misure di sicurezza tecniche e organizzative adeguate a norma dell&#039;Art. 32 del GDPR (cifratura, controllo accessi, ecc.).</span></p></li><li style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: -6pt;\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Non ricorrere a un altro responsabile (ulteriore sub-appalto) senza previa autorizzazione scritta del Responsabile.</span></p></li></ul><h2 style=\"line-height:1.2;margin-top:11.25pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>3. Assistenza e Diritti degli Interessati</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il Sub-Responsabile assiste il Responsabile con misure tecniche e organizzative adeguate nell&#039;evasione delle richieste di esercizio dei diritti degli interessati (Art. 15-22 GDPR) e nel garantire il rispetto degli obblighi di sicurezza e notifica di violazioni.</span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>4. Notifica di Data Breach</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">In caso di violazione dei dati personali (Data Breach), il Sub-Responsabile si impegna a notificare l&#039;evento al Responsabile entro e non oltre </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>24 ore</strong></span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> dal momento in cui ne è venuto a conoscenza, fornendo tutti i dettagli necessari per la comunicazione al Titolare e al Garante.</span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>5. Audit e Verifiche</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Il Sub-Responsabile mette a disposizione del Responsabile tutte le informazioni necessarie per dimostrare il rispetto degli obblighi di cui all&#039;Art. 28 e consente le attività di revisione, compresi gli audit fisici o logici presso le proprie sedi operative.</span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>6. Cancellazione o Restituzione dei Dati</strong></span></h2><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:22.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Alla cessazione del servizio, il Sub-Responsabile deve, a scelta del Responsabile, cancellare o restituire tutti i dati personali e cancellare le copie esistenti, salvo che la legge ne imponga la conservazione.</span></p><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Data: ____________________</span></p><table style=\"border:none;border-collapse:collapse;\"><tbody><tr style=\"height:0pt;\"><td style=\"vertical-align:top;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Firma per il Responsabile: ____________________</span></p></td><td style=\"vertical-align:top;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Firma per il Sub-Responsabile: ____________________</span></p></td></tr></tbody></table><p><br></p>',	1,	NULL,	NULL,	'2026-04-25 08:46:15',	'2026-04-25 08:46:44'),
(15,	'Onboarding landing page',	'<h1 style=\"line-height:1.2;margin-top:12pt;margin-bottom:12pt;\"><span style=\"font-size:24pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Compliance Landing Page (Lead Generation)</strong></span></h1><p style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><em>Documento di verifica preventiva da compilare per ogni nuova campagna di acquisizione lead tramite agenzie web marketing esterne.</em></span></p><h2 style=\"line-height:1.2;margin-top:0pt;margin-bottom:11.25pt;\"><span style=\"font-size:18pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>1. Informazioni Generali Campagna</strong></span></h2><table style=\"border:none;border-collapse:collapse;\"><tbody><tr style=\"height:0pt;\"><td style=\"border-left:solid #dddddd 0.75pt;border-right:solid #dddddd 0.75pt;border-bottom:solid #dddddd 0.75pt;border-top:solid #dddddd 0.75pt;vertical-align:top;background-color:#f9f9f9;padding:7.5pt 7.5pt 7.5pt 7.5pt;overflow:hidden;overflow-wrap:break-word;\" rowspan=\"1\" colspan=\"1\"><p style=\"line-height:1.2;margin-top:7.5pt;margin-bottom:7.5pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><strong>Agenzia Marketing:</strong></span></p></td><td style=\"border-left:s